/**
 * @param {string} s
 * @return {string}
 */
function solve(s) {
    const vowels = new Set(['a', 'e', 'i', 'o', 'u']);

    // Step 1: Preprocessing (Frequency and First Index)
    const freq = {};
    const firstIndex = {};
    const uniqueVowels = new Set();

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            uniqueVowels.add(char);

            // Calculate Frequency
            freq[char] = (freq[char] || 0) + 1;

            // Track First Index
            if (firstIndex[char] === undefined) {
                firstIndex[char] = i;
            }
        }
    }

    // Step 2: Determine Sorted Vowel Sequence
    let uniqueVowelArray = Array.from(uniqueVowels);

    // Custom sorting function:
    // 1. Frequency (Descending)
    // 2. First Appearance Index (Ascending)
    uniqueVowelArray.sort((a, b) => {
        const freqA = freq[a];
        const freqB = freq[b];

        // Primary sort: Frequency descending (B - A)
        if (freqB !== freqA) {
            return freqB - freqA;
        }

        // Secondary sort: First Index ascending (A - B)
        return firstIndex[a] - firstIndex[b];
    });

    // Construct the final ordered sequence of all vowels
    const sortedVowels = [];
    for (const vowel of uniqueVowelArray) {
        const count = freq[vowel];
        for (let i = 0; i < count; i++) {
            sortedVowels.push(vowel);
        }
    }

    // Step 3: Reconstruction
    let result = new Array(s.length);
    let vowelPointer = 0;

    for (let i = 0; i < s.length; i++) {
        const char = s[i];
        if (vowels.has(char)) {
            // Replace vowel with the next vowel from the sorted sequence
            result[i] = sortedVowels[vowelPointer];
            vowelPointer++;
        } else {
            // Consonants remain unchanged
            result[i] = char;
        }
    }

    return result.join('');
}

