import java.util.*;

public class Solution {

    private static final Set<Character> VOWELS = Set.of('a', 'e', 'i', 'o', 'u');

    // Helper class to store vowel metadata for sorting
    static class VowelInfo {
        char vowel;
        int frequency;
        int firstIndex;

        public VowelInfo(char vowel, int frequency, int firstIndex) {
            this.vowel = vowel;
            this.frequency = frequency;
            this.firstIndex = firstIndex;
        }
    }

    public static String solve(String s) {
        // Step 1: Preprocessing (Frequency and First Index)
        Map<Character, Integer> freq = new HashMap<>();
        Map<Character, Integer> firstIndex = new HashMap<>();

        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (VOWELS.contains(c)) {
                // Calculate Frequency
                freq.put(c, freq.getOrDefault(c, 0) + 1);

                // Track First Index
                if (!firstIndex.containsKey(c)) {
                    firstIndex.put(c, i);
                }
            }
        }

        // Step 2: Determine Sorted Vowel Sequence

        // Collect all unique vowels into a list of VowelInfo objects
        List<VowelInfo> uniqueVowelList = new ArrayList<>();
        for (char vowel : freq.keySet()) {
            uniqueVowelList.add(new VowelInfo(vowel, freq.get(vowel), firstIndex.get(vowel)));
        }

        // Custom sorting:
        // 1. Frequency (Descending)
        // 2. First Appearance Index (Ascending)
        uniqueVowelList.sort((v1, v2) -> {
            // Primary sort: Frequency descending
            if (v2.frequency != v1.frequency) {
                return v2.frequency - v1.frequency;
            }
            // Secondary sort: First Index ascending
            return v1.firstIndex - v2.firstIndex;
        });

        // Construct the final ordered sequence of all vowels
        List<Character> sortedVowelSequence = new ArrayList<>();
        for (VowelInfo info : uniqueVowelList) {
            int count = info.frequency;
            for (int i = 0; i < count; i++) {
                sortedVowelSequence.add(info.vowel);
            }
        }

        // Step 3: Reconstruction
        char[] result = s.toCharArray();
        int vowelPointer = 0;

        for (int i = 0; i < s.length(); i++) {
            char originalChar = s.charAt(i);
            if (VOWELS.contains(originalChar)) {
                // Replace vowel with the next vowel from the sorted sequence
                result[i] = sortedVowelSequence.get(vowelPointer);
                vowelPointer++;
            }
            // Consonants remain unchanged (result[i] already holds the original char)
        }

        return new String(result);
    }
}

