import java.util.*;

class Solution {
    public static String solve(String s) {
        Set<Character> vowels = new HashSet<>(Arrays.asList('a', 'e', 'i', 'o', 'u'));

        // Step 1: Preprocessing (Frequency and First Index)
        Map<Character, Integer> freq = new HashMap<>();
        Map<Character, Integer> firstIndex = new HashMap<>();
        Set<Character> uniqueVowels = new HashSet<>();

        for (int i = 0; i < s.length(); i++) {
            char charVal = s.charAt(i);
            if (vowels.contains(charVal)) {
                uniqueVowels.add(charVal);

                // Calculate Frequency
                freq.put(charVal, freq.getOrDefault(charVal, 0) + 1);

                // Track First Index
                if (!firstIndex.containsKey(charVal)) {
                    firstIndex.put(charVal, i);
                }
            }
        }

        // Step 2: Determine Sorted Vowel Sequence
        List<Character> uniqueVowelList = new ArrayList<>(uniqueVowels);

        // Custom sorting function:
        // 1. Frequency (Descending)
        // 2. First Appearance Index (Ascending)
        Collections.sort(uniqueVowelList, new Comparator<Character>() {
            @Override
            public int compare(Character a, Character b) {
                int freqA = freq.get(a);
                int freqB = freq.get(b);

                // Primary sort: Frequency descending (B - A)
                if (freqB != freqA) {
                    return Integer.compare(freqB, freqA);
                }

                // Secondary sort: First Index ascending (A - B)
                return Integer.compare(firstIndex.get(a), firstIndex.get(b));
            }
        });

        // Construct the final ordered sequence of all vowels
        List<Character> sortedVowels = new ArrayList<>();
        for (char vowel : uniqueVowelList) {
            int count = freq.get(vowel);
            for (int i = 0; i < count; i++) {
                sortedVowels.add(vowel);
            }
        }

        // Step 3: Reconstruction
        char[] result = new char[s.length()];
        int vowelPointer = 0;

        for (int i = 0; i < s.length(); i++) {
            char originalChar = s.charAt(i);
            if (vowels.contains(originalChar)) {
                // Replace vowel with the next vowel from the sorted sequence
                result[i] = sortedVowels.get(vowelPointer);
                vowelPointer++;
            } else {
                // Consonants remain unchanged
                result[i] = originalChar;
            }
        }

        return new String(result);
    }
}

